// Normalize trigger input — works for both webhook and schedule
const input = $input.first();
const body = input.json.body || input.json || {};

return [{
  json: {
    account_id: body.account_id || null,
    file_path: body.file_path || null,
    triggered_by: body.account_id ? 'webhook' : 'schedule',
  }
}];

// Load v2 outputs and changelog for all processed accounts
const stdout = $json.stdout || '';
const repoRoot = process.env.REPO_ROOT || '.';
const fs = require('fs');
const path = require('path');

// Parse run summary
let summary = {};
try {
  const summaryPath = path.join(repoRoot, 'run_summary.json');
  if (fs.existsSync(summaryPath)) {
    summary = JSON.parse(fs.readFileSync(summaryPath, 'utf8'));
  }
} catch (e) {}

const pipelineB = summary.pipeline_b || [];
const results = [];

for (const run of pipelineB) {
  if (run.status !== 'success') continue;
  const accountId = run.account_id;

  let v2Memo = null;
  let changesMd = null;
  let changesJson = null;

  try {
    const v2MemoPath = run.v2_memo_path;
    if (v2MemoPath && fs.existsSync(v2MemoPath)) {
      v2Memo = JSON.parse(fs.readFileSync(v2MemoPath, 'utf8'));
    }
    const changesMdPath = run.changes_md_path;
    if (changesMdPath && fs.existsSync(changesMdPath)) {
      changesMd = fs.readFileSync(changesMdPath, 'utf8');
    }
  } catch (e) {}

  results.push({
    json: {
      account_id: accountId,
      company_name: run.company_name || v2Memo?.company_name,
      status: 'success',
      total_changes: run.total_changes || 0,
      conflicts_resolved: run.conflicts_resolved || 0,
      v2_memo_path: run.v2_memo_path,
      v2_spec_path: run.v2_spec_path,
      changes_md_path: run.changes_md_path,
      changelog_preview: changesMd ? changesMd.substring(0, 500) + '...' : null,
    }
  });
}

if (results.length === 0) {
  return [{ json: { status: 'no_results', stdout } }];
}
return results;

// Update tracker for pipeline B completion
const item = $json;
return [{
  json: {
    ...item,
    tracker_updated: true,
    pipeline: 'pipeline_b',
  }
}];
